﻿using System;
using System.Collections.Generic;
using DG.Tweening;
using UnityEngine;
using UnityEngine.UI;

namespace Gordian
{
    public class GordianHeroView : BaseView
    {
        /* -------- AUTO GENERATED COMPONENT FIELDS START -------- */
		protected Button m_BgButton;
		protected Text m_LineText;
		protected Text m_TitleText;
		protected RectTransform m_AnimationTransform;
		protected Text m_NameText;
		protected Text m_HpText;
		protected Text m_SpeedText;
		protected Text m_ApText;
		protected Text m_DrawText;
		protected Text m_LoveText;
		protected Image m_LikeImage;
		protected Image m_HateImage;
		protected Image m_NormalImage;
		protected Text m_BagText;
		protected Button m_BagButton;
		protected RectTransform m_CardsTransform;
		protected Button m_CloseButton;
		protected RectTransform m_HeadsTransform;

		public Action OnBgButtonCallback { get; set; }
		public Action OnBagButtonCallback { get; set; }
		public Action OnCloseButtonCallback { get; set; }

		protected override void BindComponents(GameObject go)
		{
			var autoBindTool = go.GetComponent<AutoBindTool>();

			m_BgButton = autoBindTool.BindComponent<Button>(0);
			m_LineText = autoBindTool.BindComponent<Text>(1);
			m_TitleText = autoBindTool.BindComponent<Text>(2);
			m_AnimationTransform = autoBindTool.BindComponent<RectTransform>(3);
			m_NameText = autoBindTool.BindComponent<Text>(4);
			m_HpText = autoBindTool.BindComponent<Text>(5);
			m_SpeedText = autoBindTool.BindComponent<Text>(6);
			m_ApText = autoBindTool.BindComponent<Text>(7);
			m_DrawText = autoBindTool.BindComponent<Text>(8);
			m_LoveText = autoBindTool.BindComponent<Text>(9);
			m_LikeImage = autoBindTool.BindComponent<Image>(10);
			m_HateImage = autoBindTool.BindComponent<Image>(11);
			m_NormalImage = autoBindTool.BindComponent<Image>(12);
			m_BagText = autoBindTool.BindComponent<Text>(13);
			m_BagButton = autoBindTool.BindComponent<Button>(14);
			m_CardsTransform = autoBindTool.BindComponent<RectTransform>(15);
			m_CloseButton = autoBindTool.BindComponent<Button>(16);
			m_HeadsTransform = autoBindTool.BindComponent<RectTransform>(17);
		}
        /* -------- AUTO GENERATED COMPONENT FIELDS END -------- */

        // 动画组件
        private SpineComm m_SpineComm;

        private HeroVo m_Vo;

        protected override void InitView()
        {
            base.InitView();
        }

        public void InitData(List<HeroVo> heroVoList)
        {
            for (int i = 0; i < heroVoList.Count; i++)
            {
                var index = i;
                var heroVo = heroVoList[i];

                var path = AssetUtility.GetUIPrefab("GordianHeroHeadItem");
                GordianFactory.SpawnAsync(path, (go) =>
                {
                    go.SetParent(m_HeadsTransform);
                    go.transform.Reset(GordianAdjustManager.Instance.IsPC ? 0.85f : 1f);

                    var item = go.GetComponent<GordianHeroHeadItem>();
                    item.InitData(heroVo);

                    if (m_Vo != null)
                    {
                        item.SetSelected(m_Vo == heroVo);
                    }
                    else
                    {
                        item.SetSelected(index == 0);
                    }
                });
            }
        }

        public void SetCurrentHero(HeroVo vo, bool showEquip)
        {
            m_Vo = vo;

            var heroItems = m_HeadsTransform.GetComponentsInChildren<GordianHeroHeadItem>();
            foreach (var item in heroItems)
            {
                item.SetSelected(item.Vo == vo);
            }

            var baseData = vo.BaseData;

            // 战斗外获取基础值+装备值+属性奖励
            var hpMax = m_Vo.GetAttrValue(CharAttr.HpMax);
            var ap = m_Vo.GetAttrValue(CharAttr.ApAdd);
            var speed = m_Vo.GetAttrValue(CharAttr.ActionSpeed);
            var drawCount = m_Vo.GetAttrValue(CharAttr.DrawCardCount);

            // 战斗中获取当前值
            var gameEntity = GordianEntityManager.Instance.GetEntity(vo.EntityId) as IGameEntity;
            if (gameEntity != null)
            {
                hpMax = gameEntity.GetHpMax();
                ap += gameEntity.GetAttrValue(CharAttr.ApAdd);
                speed = gameEntity.GetAttrValue(CharAttr.ActionSpeed);
                drawCount = gameEntity.GetAttrValue(CharAttr.DrawCardCount);
            }

            m_NameText.text = baseData.Name;

            var love = m_Vo.Love + baseData.Likability;
            m_LoveText.text = ": " + love.ToString();

            // 最大好感度
            int finalType = m_Vo.GetLoveType();
            var colorStr = "#946B21";
            if (finalType == 1)
            {
                colorStr = "#942A21";
            }
            else if (finalType == 3)
            {
                colorStr = "#386C26";
            }
            ColorUtility.TryParseHtmlString(colorStr, out var color);
            m_LoveText.color = color;

            m_HateImage.SetActive(finalType == 1);
            m_NormalImage.SetActive(finalType == 2);
            m_LikeImage.SetActive(finalType == 3);

            m_HpText.text = hpMax.ToString();
            m_ApText.text = ap.ToString();
            m_SpeedText.text = speed.ToString();
            m_DrawText.text = drawCount.ToString();
            //m_CardNumText.text = vo.DeckCards.Count.ToString();

            // 显示装备卡
            var index = 0;
            var equipCardVoList = RoleVo.Instance.GetEquipList(vo.BaseId);
            for (int i = 0; i < m_CardsTransform.childCount; i++)
            {
                var posTransform = m_CardsTransform.GetChild(i);
                posTransform.RemoveAllChildren();

                // 隐藏不存在的插槽
                if (i >= vo.Slot)
                {
                    posTransform.SetActive(false);
                    continue;
                }
                posTransform.SetActive(true);

                // 被分享的装备没有Buff, 显示基础信息
                var tempEquipVo = equipCardVoList.GetValue(i);
                var isShared = tempEquipVo != null && tempEquipVo.IsShared;

                if (gameEntity != null && !isShared)
                {
                    var path = AssetUtility.GetUIPrefab("GordianEquipWarCard");
                    GordianFactory.SpawnAsync(path, (go) =>
                    {
                        posTransform = m_CardsTransform.GetChild(index);

                        go.SetParent(posTransform);

                        go.SetLocalScale(GordianAdjustManager.Instance.IsPC ? 1f : 0.7f);

                        var equipBaseId = 0;
                        var equipId = 0;

                        var equipVo = equipCardVoList.GetValue(index);
                        if (equipVo != null)
                        {
                            equipBaseId = equipVo.BaseId;
                            equipId = equipVo.Id;
                        }

                        var equipBaseData = ConfigSystem.Instance.GetCardData(equipBaseId);
                        var warCarVo = GordianWarCardVo.Create(vo.BaseId, vo.EntityId, equipBaseData, 0);
                        warCarVo.EquipId = equipId;

                        var card = go.GetComponent<GordianEquipWarCard>();
                        card.InitData(warCarVo);

                        index++;
                    });
                }
                else
                {
                    var path = AssetUtility.GetUIPrefab("GordianHeroEquipCard");
                    GordianFactory.SpawnAsync(path, (go) =>
                    {
                        posTransform = m_CardsTransform.GetChild(index);

                        go.SetParent(posTransform);

                        var equipBaseId = 0;
                        var equipId = 0;

                        var equipVo = equipCardVoList.GetValue(index);
                        if (equipVo != null)
                        {
                            equipBaseId = equipVo.BaseId;
                            equipId = equipVo.Id;
                        }

                        var card = go.GetComponent<GordianEquipCard>();
                        card.InitData(vo.BaseId, equipBaseId, equipId);

                        card.BuyButton.SetActive(showEquip);

                        index++;
                    });
                }
            }

            InitAnimation(vo);
        }

        protected void InitAnimation(HeroVo vo)
        {
            // 加载资源
            var baseData = vo.BaseData;
            var path = AssetUtility.GetHeroAction(baseData.Animation);

            m_AnimationTransform.RemoveAllChildren();

            GordianFactory.SpawnAsync(path, (go) =>
            {
                go.transform.SetParent(m_AnimationTransform);
                go.transform.Reset();
                go.transform.localScale = Vector3.one * baseData.Scale;

                if (baseData.Offset.Count == 2)
                {
                    go.transform.localPosition = new Vector3(baseData.Offset[0], baseData.Offset[1], 0);
                }

                // 动画组件
                m_SpineComm = go.GetOrAddCompoment<SpineComm>();
                m_SpineComm.Init(baseData.Animation);
            });
        }

        public void SetHit()
        {
            if (m_SpineComm)
            {
                m_SpineComm.SetHit();
            }
        }

        protected override void InitEvent()
        {
            m_BgButton.onClick.AddListener(OnCloseButton);
            m_CloseButton.onClick.AddListener(OnCloseButton);
            m_BagButton.onClick.AddListener(OnBakckpackButton);
        }

        private void OnBakckpackButton()
        {
            var callback = (OpenFormCallback)((logic) =>
            {
                var panel = logic as GordianBagPanel;
                panel.InitData(m_Vo);
            });
            GordianUIManager.Instance.OpenForm(UIFormId.GordianBagPanel, callback);
        }

        private void OnCloseButton()
        {
            GordianUIManager.Instance.CloseForm(UIFormId.GordianHeroPanel);
        }

        protected override void RemoveEvent()
        {
            base.RemoveEvent();
        }

        public override void Close()
        {
            base.Close();

            if (m_SpineComm != null)
            {
                m_SpineComm.skeletonGraphic.DOKill();
                m_SpineComm.gameObject.Restore();
                m_SpineComm = null;
            }

            m_HeadsTransform.RemoveAllChildren();
            m_AnimationTransform.RemoveAllChildren();

            var equipCards = m_CardsTransform.GetComponentsInChildren<GordianEquipCard>(true);
            for (int i = equipCards.Length - 1; i >= 0; i--)
            {
                equipCards[i].Remove();
            }
        }

        public void ShowLove(bool value)
        {
            m_LoveText.transform.parent.SetActive(value);
        }
    }
}

