﻿using UnityEngine;
using UnityEngine.UI;

namespace Gordian
{

    public class GordianEquipItem : BaseItem
    {
        /* -------- AUTO GENERATED COMPONENT FIELDS START -------- */
		protected HorizontalLayoutGroup m_CardsHGroup;

		protected override void BindComponents(GameObject go)
		{
			var autoBindTool = go.GetComponent<AutoBindTool>();

			m_CardsHGroup = autoBindTool.BindComponent<HorizontalLayoutGroup>(0);
		}
        /* -------- AUTO GENERATED COMPONENT FIELDS END -------- */

        private GordianCardShopHeroItem m_HeroItem;

        private GordianEquipItemVo m_Vo;
        public GordianEquipItemVo Vo => m_Vo;

        private float m_OriginSpacing;

        protected override void InitView()
        {
            base.InitView();

            m_HeroItem = transform.GetComponentInChildren<GordianCardShopHeroItem>(true);

            m_OriginSpacing = m_CardsHGroup.spacing;
        }

        protected override void InitEvent()
        {

        }

        protected override void RemoveEvent()
        {
        }

        public override void Remove()
        {
            base.Remove();

            m_CardsHGroup.spacing = m_OriginSpacing;
        }

        public void InitData(GordianEquipItemVo vo)
        {
            m_Vo = vo;

            m_HeroItem.InitData(m_Vo.HeroVo);

            var heroBaseId = m_Vo.HeroVo.BaseId;
            for (int i = 0; i < m_CardsHGroup.transform.childCount; i++)
            {
                var posTransform = m_CardsHGroup.transform.GetChild(i);

                var card = posTransform.GetComponentInChildren<GordianEquipCard>(true);
                if (m_Vo.EquipList.Count > i)
                {
                    var cardVo = m_Vo.EquipList[i];
                    card.InitData(heroBaseId, cardVo.BaseId, cardVo.Id);
                }
                else
                {
                    card.InitData(heroBaseId, 0, 0);
                }

                if (m_Vo.HeroVo.Slot == GordianConfig.EquipSlot)
                {
                    // 2个中间间距大一点
                    m_CardsHGroup.spacing = GordianAdjustManager.Instance.IsPC ? 200 : 80;
                }
                else
                {
                    m_CardsHGroup.spacing = m_OriginSpacing;
                }
                card.transform.parent.SetActive(m_Vo.HeroVo.Slot > i);
            }
        }
    }
}

