﻿using Dida.GameLogic.Common;
using GameFramework.Event;

namespace Gordian
{
    public class GordianHeroPanel : BaseController
    {
        private GordianHeroModel m_Model;
        private GordianHeroView m_View;

        protected override void OnInit(object userData)
        {
            base.OnInit(userData);

            m_Model = InitModel<GordianHeroModel>();
            m_View = m_IsPC ? InitView<GordianHeroPCView>() : InitView<GordianHeroView>();

            m_Model.HeroVoList = RoleVo.Instance.HeroList;
        }

        protected override void InitEvent()
        {
            EventSystem.Instance.Subscribe<UIEquipCardClickEvent>(OnUIEquipClickEvent, this);
            EventSystem.Instance.Subscribe<UICardDetailEquipEvent>(OnUICardDetailEquipEvent, this);
            EventSystem.Instance.Subscribe<UIRemoveEquipEvent>(OnUIRemoveEquipEvent, this);

            EventSystem.Instance.Subscribe<UIHeroHeadItemEvent>(OnHeroHeadItemEvent, this);

            EventSystem.Instance.Subscribe<HeroAddCardEvent>(OnAddHeroCardEvent, this);
        }

        public void InitData(bool showEquip)
        {
            m_Model.ShowEquip = showEquip;

            m_View.InitData(m_Model.HeroVoList);
        }

        private void OnUIRemoveEquipEvent(object sender, GameEventArgs e)
        {
            var data = e as UIRemoveEquipEvent;
            // 卸下当前装备
            RoleVo.Instance.UnEquip(data.EquipId, true);

            SetCurrentHero(m_Model.CurrentHeroVo);

            GordianUIManager.Instance.CloseForm(UIFormId.GordianEquipmentBagPanel);
        }

        private void OnUIEquipClickEvent(object sender, GameEventArgs e)
        {
            var data = e as UIEquipCardClickEvent;

            m_Model.CurrentEquipId = data.EquipId;

            var callback = (OpenFormCallback)((logic) =>
            {
                var panel = logic as GordianEquipmentBagPanel;
                panel.InitData((int)EquipBagShowType.Normal, m_Model.CurrentEquipId);
            });
            GordianUIManager.Instance.OpenForm(UIFormId.GordianEquipmentBagPanel, callback);
        }

        private void OnUICardDetailEquipEvent(object sender, GameEventArgs e)
        {
            var data = e as UICardDetailEquipEvent;

            var heroVo = m_Model.CurrentHeroVo;
            var newEquipVo = data.EquipVo;

            var pos = RoleVo.Instance.GetEquipList(heroVo.BaseId).Count;
            // 移除当前装备
            var currentEquipVo = RoleVo.Instance.GetEquip(m_Model.CurrentEquipId);
            if (currentEquipVo != null)
            {
                pos = currentEquipVo.Pos;

                RoleVo.Instance.UnEquip(currentEquipVo.Id);
            }


[77 more lines in file. Use offset=81 to continue.]

            // 佩戴新装备
            if (newEquipVo != null)
            {
                // 替换
                if (newEquipVo.HeroBaseId != 0)
                {
                    if (currentEquipVo != null)
                    {
                        currentEquipVo.HeroBaseId = newEquipVo.HeroBaseId;
                        currentEquipVo.Pos = newEquipVo.Pos;
                    }
                }

                RoleVo.Instance.Equip(newEquipVo.Id, heroVo.BaseId, pos);
            }

            SetCurrentHero(heroVo);

            GordianUIManager.Instance.CloseForm(UIFormId.GordianEquipmentBagPanel);
        }

        private void OnAddHeroCardEvent(object sender, GameEventArgs e)
        {
            var data = e as HeroAddCardEvent;
            var heroVo = m_Model.GetHero(data.HeroBaseId);
            if (heroVo != null)
            {
                SetCurrentHero(heroVo);
            }
        }

        private void OnHeroHeadItemEvent(object sender, GameEventArgs e)
        {
            var data = e as UIHeroHeadItemEvent;
            SetCurrentHero(data.HeroVo);
        }

        protected override void OnOpen(object userData)
        {
            base.OnOpen(userData);
        }

        public void SetCurrentHeroIndex(int index)
        {
            if (m_Model.HeroVoList.Count > index)
            {
                SetCurrentHero(m_Model.HeroVoList[index]);
            }
        }

        public void SetCurrentHero(HeroVo vo)
        {
            m_Model.SetCurrentHero(vo);

            m_View.SetCurrentHero(vo, m_Model.ShowEquip);

            // 普通难度显示好感度
            var chooseLevel = GordianUserInfo.Instance.GetGordianChooseTowerLevel();
            m_View.ShowLove(chooseLevel <= 1);

            // 播放音效
            var voice = vo.BaseData.Voice.GetValue(vo.GetLoveType() - 1);
            if (!string.IsNullOrEmpty(voice))
            {
                AudioCtrl.PlaySound(voice);
            }

            // 播放音效
            var voice3 = vo.BaseData.Voice3;
            if (!string.IsNullOrEmpty(voice3))
            {
                AudioCtrl.PlaySound(voice3);
            }
        }
    }
}
